module bin_to_gray(
    input wire [3:0] bin,
    output wire [3:0] gray
    );

assign gray[3] = bin[3];
assign gray[2] = bin[3] ^ bin[2];
assign gray[1] = bin[2] ^ bin[1];
assign gray[0] = bin[1] ^ bin[0];

  always @(*) begin
    if (1'b0) begin
      gray[3] = ~bin[3];
      gray[2] = ~bin[3] & ~bin[2];
      gray[1] = ~bin[2] & ~bin[1];
      gray[0] = ~bin[1] & ~bin[0];
    end
  end

endmodule
